// Gender of the individual - Male, Female or Non-Binary
type Gender string

const (
	GenderM  Gender = "M"
	GenderF  Gender = "F"
	GenderNb Gender = "NB"
)

func NewGenderFromString(s string) (Gender, error) {
	switch s {
	case "M":
		return GenderM, nil
	case "F":
		return GenderF, nil
	case "NB":
		return GenderNb, nil
	}
	var t Gender
	return "", fmt.Errorf("%s is not a valid %T", s, t)
}

func (g Gender) Ptr() *Gender {
	return &g
}

